VALUES
  ('customs-f19eb2bd-moex-00447', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「總是嚮往一處可以憩息的地方，好讓你卸下肩頭的重擔，有人叫著你的 名字，像百年榕樹永遠認得飄零的葉子。啊，家的感覺或許很簡單，不管 飄盪多少年，衣衫如何襤褸，老宅旁邊榕蔭下，有一塊石墩讓你小坐，下 弈的老人數算將士兵馬，還不忘告訴你，這兒有冰鎮的麥茶。沒有人攻訐 你的過往，古井流水依然清澈，你可以洗癒炎涼江湖烙在身上的傷疤，你 無需在惡意的詆毀中像奔逃的小鹿，亦不必沈溺於浮名如迷途的羔羊，你 只是一個願意關愛他人也被呵護著的人，你是春雀的同伴，流雲的知己。 月亮照耀青窗，窗裡窗外皆有青色的光。不管遠方如何聲討你是背信的人， 月光下總有一扇青窗，堅持說你是唯一被等待的人。」根據上文，下列選 項何者最符合作者意旨？', '["人生如逆旅，我們不斷飄盪在這處那處之間", "家鄉永遠只存留在模糊的記憶之中供人憑弔", "純樸而溫厚的鄉村是旅遊與休閒的最佳去處", "家鄉永遠敞開溫暖雙臂迎接漂泊的遊子歸來"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 46, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00448', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「望著海洋一陣的強風帶給海面一大片的灰暗，景象帶來淒涼的落寂感， 洞裡的青煙使我想到拓拔斯（布農族）的小說《最後的獵人》裡的男主角 比雅日和妻子帕蘇拉的故事。帕蘇拉對比雅日說：『……如果你聽我的話 到平地做臨時綑工，買幾件毛衣就不需為冷天劈柴烤火取暖……。』但比 雅日終究沒有去平地做綑工，反而上山去打獵；因為只有在深山才覺得有 尊嚴，有智慧，真正展露布農男人的氣魄。雖然在回部落途中他的獵物被 檢查哨的惡警擄走，僅留給他一隻狐狸孝敬帕蘇拉。比雅日無膽怨嘆，只 覺得惡質剝削在越為複雜的社會裡如鬼魂般地經常的，自然的落在弱勢、 窮人的命運裡。」下列選項，最符合本文旨意的是：', '["以客觀的角度分析原住民族文化在現實社會中的優勢與劣勢", "即使生活受到壓迫，仍無法取代原住民族對自身文化的熱愛", "認為原住民族文化是其唯一的依歸，只有與外界阻隔才能保留", "作者對於原住民族文化的關懷，盼望政府能給予原住民族工作機會"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 47, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00449', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '繪本《活了一百萬次的貓》作者佐野洋子面對癌轉移的任性態度，堪稱經 典。洋子只問醫師兩個問題：「還有幾年？」「到死之前要花多少錢？」 確定錢都夠花，立刻決定：「請不要延長我的壽命。」然後在回家路上， 走進名車代理店，指著英格蘭綠的積架說：「買了。」「得知還有兩年可 活，折磨了我數十年的憂鬱症也好了！」她說知道自己的死期，也得到了 自由。佐野洋子真是神奇歐巴桑。看來，自知死之將至，也沒什麼不好， 重要的是我們能不能有足夠的自由，選擇走到生命末日的方式。根據上文， 下列選項最接近作者人生旨趣的是：', '["反對佐野洋子癌症轉移後放棄治療", "人自知死亡之將至有益治療憂鬱症", "只要財力足夠就可以安享生命末期", "人即使到生命末期也要能自主安頓"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 48, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00450', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「有一個『雁行理論』說，當雁鼓動雙翼時，對尾隨的同伴具有『鼓舞』 的作用，雁群一字排開成V字型時，比孤雁單飛增加了七成的飛行距離。 一般來說，不論何時，當一隻雁脫離隊伍，牠馬上會感受到一股動力阻止 牠離開，藉著前一隻夥伴的『支撐力』，牠很快便能回到隊伍。此外，在 一個雁陣中，當帶頭的雁疲倦了，牠會退回隊伍，由另一隻取代牠的位置。 同時，在雁陣隊伍中後面的雁，會以叫聲鼓勵前面的夥伴繼續前進；當有 雁隻生病或受傷時，其他兩隻會由隊伍飛下來協助及保護牠，這兩隻雁便 一直陪伴牠到康復或死亡為止，然後牠們自己組成隊伍再開始飛行，或者 去追趕上原來的雁群。」根據上文「雁行理論」所帶給人們的啟示，下列 選項何者錯誤？', '["留在與自己目標一致的隊伍，並且樂意接受他人的協助，便能使團隊邁 向成功之路", "與擁有相同目標的人同行，因著彼此之間的互相推動，便能快速、容易 地到達目的地", "為避免拖累團隊達標進展，就算眼前困難重重，也要抱著捨我其誰的精 神，繼續拼搏", "適時給予團隊夥伴讚美與鼓勵，能使團隊挺過艱難的時刻、有動力持續 努力並達成目標"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 49, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00451', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-01c5eaab', 'sub-customs-f19eb2bd-05', NULL, 'single_choice', '「在我們空前焦慮自己是個沒故事、沒身世、沒歷史的——民族？島嶼？ 國家？——的此時此際，難道我們甘心注定永遠是個樹小牆新、沒有積累、 沒有記憶，因此對這個地方也沒有什麼不可讓渡的感情的民族？島嶼？國 家？格雷安．葛林在《哈瓦那特派員》寫過：『人口研究報告可以印出各 種統計數值、城市人口，藉以描繪一個城市。但對城裡的每個人而言，所 謂城市不過是幾條巷道、幾間房子和幾個人的組合，沒有了這些，一個城 市形同隕落，只剩下悲涼的記憶，那種痛苦就像失去了一條腿般的空虛。』 說得真好，不是嗎？」根據上文，下列選項何者錯誤？', '["城市的故事來自於人與環境的組合", "沒有身世的城市無法累積認同的情感", "人口研究報告可具體看出城市發展軌跡", "城市沒有自己的歷史可能使居民感到焦慮"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "0a3cefc62999", "answer_pdf_sha1": "c716b3130813", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 50, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00452', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '在麥氏海圖上，用低緯度之比例尺量取高緯度之距離會發生何種現象？', '["量得之結果即為實際的距離之一半", "量得之結果即為實際的距離", "量得之結果會比實際的距離大", "量得之結果會比實際的距離小"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00453', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '某船由35°N先向南航行300浬，再分別向西、向北和向東各航行300浬，則該船最終到達點位於起始點 的何方？', '["同一點", "東方", "西方", "東南方"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00454', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '下列海圖中，何者不是屬於正形海圖？', '["大圈海圖", "定位圖紙（PlottingSheet）", "麥氏海圖", "蘭伯特海圖"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00455', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '預估航向受水流或風等影響後船隻所行駛之估計路線，稱之為何？', '["對地航向", "實際航向", "航跡", "航向線"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL),
  ('customs-f19eb2bd-moex-00456', 'customs-f19eb2bd', 'customs-f19eb2bd-moex-111-248a632e', 'sub-customs-f19eb2bd-02', NULL, 'single_choice', '下列何者不是疊標的功能？', '["標示障礙物所在", "測速", "導航", "校對羅經"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:22:27+00:00", "source_pdf_sha1": "8eaf9dfad9c2", "answer_pdf_sha1": "47a63ea8ad21", "source_family": "moex-gov-tw", "moex": {"exam_code": "111050", "c": "151", "s": "2002", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "航海船藝大意", "year": "111", "exam_name": "111年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "customs", "civil_category": "船舶駕駛"}'::jsonb, NULL)
